"import pytest\nfrom app.services.physics_engine import PhysicsEngine\n\ndef test_free_fall():\n    res = PhysicsEngine.solve_free_fall(height=50.0, mass=1.0, gravity=9.81)\n    \n    assert \"metrics\" in res\n    assert \"chart_data\" in res\n    \n    metrics = res[\"metrics\"]\n    assert metrics[\"time_of_flight\"] > 0\n    assert \"velocity_impact\" in metrics\n    assert \"energy_kinetic_max\" in metrics\n\ndef test_pendulum():\n    res = PhysicsEngine.solve_pendulum(length=2.5, angle_deg=45.0, mass=1.2, gravity=9.81, damping=0.0)\n    \n    metrics = res[\"metrics\"]\n    assert metrics[\"period\"] > 0\n    assert metrics[\"angular_frequency\"] > 0\n    \ndef test_collision():\n    res = PhysicsEngine.solve_collision(mass_a=2.0, mass_b=1.5, vel_a=5.0, vel_b=-3.0, collision_type=\"Elastic\")\n    \n    metrics = res[\"metrics\"]\n    assert metrics[\"total_momentum\"] == 5.5  # (2.0 * 5.0) + (1.5 * -3.0) = 10.0 - 4.5 = 5.5\n    assert metrics[\"kinetic_energy_lost\"] >= 0.0\n"